929				       PATHSPEC_LITERAL_PATH, "", args.v);
930			res = run_add_p(s->r, ADD_P_ADD, &opts, NULL, &ps_selected, 0);
931			strvec_clear(&args);
932			clear_pathspec(&ps_selected);
933		}
934	
935		return res;
936	}
