1109	
1110		/*
1111		 * When color was asked for, use the prompt color for
1112		 * highlighting, otherwise use square brackets.
1113		 */
1114		if (want_color(s.cfg.use_color_interactive)) {
1115			data.color = s.cfg.prompt_color;
