1133	
1134		for (;;) {
1135			struct command_item *util;
1136	
1137			i = list_and_choose(&s, &commands, &main_loop_opts);
1138			if (i < 0 || i >= commands.items.nr)
1139				util = NULL;
1140			else
1141				util = commands.items.items[i].util;
1142	
1143			if (i == LIST_AND_CHOOSE_QUIT || (util && !util->command)) {
1144				printf(_("Bye.\n"));
